mapper.select:
select cs.id, c.id as courseId, c.course_name, c.credit, s.name as semester_name, cs.status, cs.score, cs.score_point
from course_selection cs
inner join (
    select max(id) as id
    from course_selection

        student_id = #{studentId}
        and semester_id = #{semesterId}
        and status = #{status}

    group by student_id, course_id
) latest on cs.id = latest.id
left join course c on cs.course_id = c.id
left join semester s on cs.semester_id = s.id
order by cs.id desc

select cs.id, cs.course_id, cs.student_id as studentId, stu.name as student_name, c.course_name, c.credit, s.name as semester_name, cs.status, cs.score, cs.score_point, cs.create_time as createTime, cs.update_time as updateTime
from course_selection cs
         left join course c on cs.course_id = c.id
         left join student stu on cs.student_id = stu.id
         left join semester s on cs.semester_id = s.id

    cs.student_id = #{studentId}
    and cs.course_id = #{courseId}
    and cs.semester_id = #{semesterId}
    and cs.status = #{status}
